INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('locality-814ced5a-moex-00116', 'locality-814ced5a', 'locality-814ced5a-moex-111-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '「所謂品字，其義即是能久經玩味之意。人品高即此人能經得起時間的考驗。」 下列選項，最能呼應上述文意的是：', '["勁草不隨風偃去", "天生我材必有用", "人生樂在相知心", "不遭人忌是庸才"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "e90a507a577f", "answer_pdf_sha1": "69eb6bd30069", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00117', 'locality-814ced5a', 'locality-814ced5a-moex-111-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '「你永遠記得，上天給每一個人禮物；但是，卻不告訴你禮物放在哪裡，你必須自己去找。有人很快 找到，你現在沒找到，不代表二十歲時找不到；二十歲沒找到，不代表三十歲找不到。有些禮物非常 特殊，首先要訓練你的力氣，你才能打得開那禮物，我也曾經認為上天沒給我禮物，後來才發現真的 有給我。」 根據上文，下列選項何者最接近本文的旨意？', '["每個人都有幸與不幸，因此我們應當學會憐憫不幸的人", "每個人都有獨特的天賦，經常需要自覺鍛鍊，才能發掘", "因歲月流逝，人可能獲得的經驗越來越多，也越加世故", "越年輕的時候，體力越充沛，比較能挑戰自己達成目標"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "e90a507a577f", "answer_pdf_sha1": "69eb6bd30069", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00118', 'locality-814ced5a', 'locality-814ced5a-moex-111-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '運動選手說：「大家都認為你得獎是應該的，一度練到身心疲憊，覺得自己好像奪牌道具，奪牌還會 被說不能太驕傲。我從頭到尾都沒有很驕傲，只是希望疲憊時，想休息的需求可以被好好回應，希望 能被肯定，說：你做得很好，即便不是第一名也沒關係，你有拿到一塊牌就很厲害了，但這樣的肯定 並不多，也讓我有一度失去熱情，不再是開心參加比賽，而是背負著一個使命，去做別人期待的那些 事情。」 下列選項，何者最符合選手的心境？', '["獲得獎牌後，選手因此能繼續開心參加比賽", "因為一直得獎，深怕自己太驕傲，而感到焦慮", "希望大家認可自己的努力，不要只期待能拿下第一名", "由於失去熱情，因此得不到肯定，所以讓選手身心疲憊"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "e90a507a577f", "answer_pdf_sha1": "69eb6bd30069", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00119', 'locality-814ced5a', 'locality-814ced5a-moex-111-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '「在臺灣，兒童的社會定位在戰後數十年間有明顯的變化。在充斥反共宣傳的年代，養育兒童旨在培 養國家的戰備力和家庭的勞動力。隨著經濟起飛與政治民主化，兒童逐步轉變為消費、教育、福利的 主體，因而其脆弱性逐漸被放大。社會菁英要求國家改革教育體制，『愛的教育』成為教養的新正統， 以確保孩子獲得足夠的學習刺激與認知發展，並維護孩子的快樂童年、自主權益。」 下列選項，最符合本文意旨的是：', '["臺灣兒童在戰後期間隨著教養觀念的轉變，而變得越來越脆弱", "反共年代為培養國家戰備力與家庭勞動力，政府改革教育體制", "兒童之所以成為消費教育和福利的主體，是因少子化問題嚴重", "現代強調愛的教育，是正視兒童成長的脆弱性而給予保護養育"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "e90a507a577f", "answer_pdf_sha1": "69eb6bd30069", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00120', 'locality-814ced5a', 'locality-814ced5a-moex-111-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '「如果你記得某個作者所說的話，就是在閱讀中學到了東西。如果他說的都是真的，你甚至學到了有 關這個世界的某種知識；但是，不管學到的是有關這本書的知識或有關世界的知識，如果運用的只是 記憶力，其實除了那些訊息之外一無所獲，你並沒有被啟發。要能被啟發，除了知道作者所說的話之 外，還要明白他的意思，懂得他為什麼會這麼說。」 根據上文，下列選項最接近文意的是：', '["閱讀最重要的收穫是記住作者的話並且運用在生活當中", "作者認為閱讀是運用記憶力將龐雜知識加以整合及分類", "較高層次的閱讀包括理解文意、寫作動機以及延伸思考", "啟發式閱讀是運用記憶力以精確掌握書本與世界的知識"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "e90a507a577f", "answer_pdf_sha1": "69eb6bd30069", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00121', 'locality-814ced5a', 'locality-814ced5a-moex-111-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '「2018年《自然》雜誌報導指出，當你在ImageNet這個非常大型的影像資料庫裡面，上傳一張身穿白 紗的美國新娘照片時，會得到『新娘』、『禮服』、『女人』、『婚禮』等文字描述，但如果你上傳一張印 度新娘傳統禮服的照片時，得到的卻會是『表演藝術』、『戲服』等描述，為什麼會這樣？原來，這個 資料庫裡面有45%的資料來自於美國，但來自於印度的資料卻不到3%，而人工智慧依據這樣的資料 庫內容進行辨識而產生誤差。」 根據上文，下列選項何者最符合文意？', '["ImageNet資料庫大量圖像是由AI自動生成", "上傳資料庫的使用者帶有種族歧視的偏見", "人工智慧辨識技術無法真實反映文化差異", "業者為求快速增加點閱率而上傳各種資訊"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "e90a507a577f", "answer_pdf_sha1": "69eb6bd30069", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00122', 'locality-814ced5a', 'locality-814ced5a-moex-111-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '「當美觸碰到心坎深處，迎面突然劈來意外的畫面，某區石窟正在修葺，外頭搭著大片鷹架，讓窟洞 在後方若隱若現。我忽然從陶醉裡醒了，徹徹底底。那一瞬了然千年生命本來就會起伏、會殘缺，需 要縫補。」 根據上文，何者最接近作者在參觀雲岡石窟所得到的體悟？', '["美是永恆性的存在，蝕刻在天地間", "不論美或醜，都是不朽的文化瑰寶", "輝煌的文化寶藏，其實比想像脆弱", "文物的價值應內外兼具，細心呵護"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "e90a507a577f", "answer_pdf_sha1": "69eb6bd30069", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00123', 'locality-814ced5a', 'locality-814ced5a-moex-111-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '詩人愛默生說：「每當我讀到好書，我真希望人的一生可以有三千年。」下列選項，最符合文意的是：', '["希望有充分的時間可以讀盡天下的好書", "渴望融入書本，徜徉在想像的時空當中", "閱讀好書美好的感覺彷彿三千年如一日", "書的內容艱澀需要仔細閱讀長時間體會"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "e90a507a577f", "answer_pdf_sha1": "69eb6bd30069", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00124', 'locality-814ced5a', 'locality-814ced5a-moex-111-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '「雖然和貝多芬《命運交響曲》相似，也從c小調寫到C大調，蕭斯塔科維契《第八號交響曲》卻不 見勝利，僅是浩劫餘生。那是作曲家眼看二戰失控，家鄉圍城之役慘絕人寰，發自內心的怒吼哭嚎。 他展現全能作曲能力，讓所有章法、格式、規矩都為他說話。」 根據上文，下列選項何者最符合《第八號交響曲》所表達的情感？', '["陷於眾聲喧嘩", "等待凱旋榮歸", "受苦憤怒悲愴", "平靜沉默無語"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "e90a507a577f", "answer_pdf_sha1": "69eb6bd30069", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00125', 'locality-814ced5a', 'locality-814ced5a-moex-111-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '「老師絕不會想過早使學生成為藝術家，他的首要考量是使學生成為一個技巧純熟的工匠。學生勤勉 地貫徹老師的想法，近乎愚鈍地低頭努力。若干年後他一天比一天更能追求他的靈感，不需要在技術 上費力，同時他也能透過細心的觀察而啟發靈感。他心中剛浮現意象，手中的筆已將那意象捕捉描繪 下來，完成了創作。」 根據上文，作者對藝術教育的理念，下列選項何者正確？', '["抱負與責任雖愚鈍但功不可沒", "技巧純熟優於藝術創作的展現", "靈感的培養形成不費吹灰之力", "純熟的工匠技術是藝術的基礎"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "e90a507a577f", "answer_pdf_sha1": "69eb6bd30069", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL)
